part 'items_provider.g.dart';

@riverpod
class Items extends _$Items {
  @override
  Future<List<Item>> build() async {
    // Simulate loading items from storage/API
    await Future.delayed(const Duration(milliseconds: 500));

    return [
      Item(
        id: 1,
        title: 'Basic Calculations',
        description: 'Simple arithmetic operations',
        createdAt: DateTime.now().subtract(const Duration(days: 1)),
      ),
      Item(
        id: 2,
        title: 'Scientific Functions',
        description: 'Trigonometric and logarithmic functions',
        createdAt: DateTime.now(),
      ),
    ];
  }

  Future<void> addItem(String title, String? description) async {
    state = const AsyncValue.loading();

    state = await AsyncValue.guard(() async {
      final currentItems = await future;
      final newId = currentItems.isEmpty ? 1 : currentItems.map((i) => i.id).reduce((a, b) => a > b ? a : b) + 1;

      final newItem = Item(
        id: newId,
        title: title,
        description: description,
        createdAt: DateTime.now(),
      );

      return [...currentItems, newItem];
    });
  }

  Future<void> removeItem(int id) async {
    state = const AsyncValue.loading();

    state = await AsyncValue.guard(() async {
      final currentItems = await future;
      return currentItems.where((item) => item.id != id).toList();
    });
  }

  Future<void> updateItem(int id, String title, String? description) async {
    state = const AsyncValue.loading();

    state = await AsyncValue.guard(() async {
      final currentItems = await future;
      return currentItems.map((item) {
        if (item.id == id) {
          return item.copyWith(
            title: title,
            description: description,
          );
        }
        return item;
      }).toList();
    });
  }

  Future<void> refresh() async {
    ref.invalidateSelf();
  }
}

