  @override
  AppSettings build() {
    return const AppSettings(
      isDarkTheme: false,
      notificationsEnabled: true,
      decimalPrecision: 4,
    );
  }

  void toggleTheme() {
    state = state.copyWith(isDarkTheme: !state.isDarkTheme);
  }

  void toggleNotifications() {
    state = state.copyWith(notificationsEnabled: !state.notificationsEnabled);
  }

  void setDecimalPrecision(int precision) {
    if (precision >= 2 && precision <= 10) {
      state = state.copyWith(decimalPrecision: precision);
    }
  }

  void clearHistory() {
    // Implementation for clearing calculation history
    // This would typically interact with a history provider
  }

  void resetToDefaults() {
    state = const AppSettings(
      isDarkTheme: false,
      notificationsEnabled: true,
      decimalPrecision: 4,
    );
  }
}

import 'package:flutter/material.dart';

class AppSettings {
  final bool isDarkTheme;
  final bool notificationsEnabled;
  final int decimalPrecision;

  const AppSettings({
    required this.isDarkTheme,
    required this.notificationsEnabled,
    required this.decimalPrecision,
  });

  AppSettings copyWith({
    bool? isDarkTheme,
    bool? notificationsEnabled,
    int? decimalPrecision,
  }) {
    return AppSettings(
      isDarkTheme: isDarkTheme ?? this.isDarkTheme,
      notificationsEnabled: notificationsEnabled ?? this.notificationsEnabled,
      decimalPrecision: decimalPrecision ?? this.decimalPrecision,
    );
  }

  @override
  bool operator ==(Object other) {
    if (identical(this, other)) return true;
    return other is AppSettings &&
        other.isDarkTheme == isDarkTheme &&
        other.notificationsEnabled == notificationsEnabled &&
        other.decimalPrecision == decimalPrecision;
  }

  @override
  int get hashCode {
    return isDarkTheme.hashCode ^
        notificationsEnabled.hashCode ^
        decimalPrecision.hashCode;
  }

  @override
  String toString() {
    return 'AppSettings(isDarkTheme: $isDarkTheme, notificationsEnabled: $notificationsEnabled, decimalPrecision: $decimalPrecision)';
  }
}

class Item {
  final int id;
  final String title;
  final String? description;
  final DateTime createdAt;

  const Item({
    required this.id,
    required this.title,
    this.description,
    required this.createdAt,
  });

  Item copyWith({
    int? id,
    String? title,
    String? description,
    DateTime? createdAt,
  }) {
    return Item(
      id: id ?? this.id,
      title: title ?? this.title,
      description: description ?? this.description,
      createdAt: createdAt ?? this.createdAt,
    );
  }

  @override
  bool operator ==(Object other) =>
      identical(this, other) ||
      other is Item &&
          runtimeType == other.runtimeType &&
          id == other.id &&
          title == other.title &&
          description == other.description &&
          createdAt == other.createdAt;

  @override
  int get hashCode =>
      id.hashCode ^
      title.hashCode ^
      description.hashCode ^
      createdAt.hashCode;

  @override
  String toString() {
    return 'Item{id: $id, title: $title, description: $description, createdAt: $createdAt}';
  }
}

import 'package:flutter/material.dart';
import 'package:flutter_riverpod/flutter_riverpod.dart';
