import 'package:a_scientific_calculator_application_to_perform_mor/features/calculator/providers/calculator_provider.dart';

class HomeScreen extends ConsumerWidget {
  const HomeScreen({super.key});

  @override
  Widget build(BuildContext context, WidgetRef ref) {
    final calculatorState = ref.watch(calculatorProvider);
    final calculatorNotifier = ref.read(calculatorProvider.notifier);

    return Scaffold(
      appBar: AppBar(
        title: const Text('Scientific Calculator'),
        actions: [
          IconButton(
            icon: const Icon(Icons.settings),
            onPressed: () => context.go('/settings'),
          ),
        ],
      ),
      body: Column(
        children: [
          // Display
          Container(
            width: double.infinity,
            padding: const EdgeInsets.all(24),
            decoration: BoxDecoration(
              color: Theme.of(context).colorScheme.surfaceVariant,
              borderRadius: const BorderRadius.vertical(
                bottom: Radius.circular(16),
              ),
            ),
            child: Column(
              crossAxisAlignment: CrossAxisAlignment.end,
              children: [
                Text(
                  calculatorState.display,
                  style: Theme.of(context).textTheme.headlineLarge?.copyWith(
                    color: calculatorState.hasError 
                        ? Theme.of(context).colorScheme.error
                        : null,
                  ),
                  textAlign: TextAlign.end,
                ),
                if (calculatorState.hasError && calculatorState.errorMessage.isNotEmpty)
                  Text(
                    calculatorState.errorMessage,
                    style: Theme.of(context).textTheme.bodySmall?.copyWith(
                      color: Theme.of(context).colorScheme.error,
                    ),
                  ),
              ],
            ),
          ),

          // Calculator Buttons
          Expanded(
            child: Padding(
              padding: const EdgeInsets.all(16),
              child: Column(
                children: [
                  // First Row - Clear, Backspace, Square Root, Divide
                  Expanded(
                    child: Row(
                      children: [
                        _buildButton(
                          context,
                          'C',
                          onPressed: calculatorNotifier.clear,
                          isOperator: true,
                        ),
                        _buildButton(
                          context,
                          '⌫',
                          onPressed: calculatorNotifier.backspace,
                          isOperator: true,
                        ),
                        _buildButton(
                          context,
                          '√',
                          onPressed: calculatorNotifier.squareRoot,
                          isOperator: true,
                        ),
                        _buildButton(
                          context,
                          '÷',
                          onPressed: () => calculatorNotifier.inputOperator('/'),
                          isOperator: true,
                        ),
                      ],
                    ),
                  ),

                  // Second Row - 7, 8, 9, Multiply
                  Expanded(
                    child: Row(
                      children: [
                        _buildButton(context, '7', onPressed: () => calculatorNotifier.inputNumber('7')),
                        _buildButton(context, '8', onPressed: () => calculatorNotifier.inputNumber('8')),
                        _buildButton(context, '9', onPressed: () => calculatorNotifier.inputNumber('9')),
                        _buildButton(
                          context,
                          '×',
                          onPressed: () => calculatorNotifier.inputOperator('*'),
                          isOperator: true,
                        ),
                      ],
                    ),
                  ),

                  // Third Row - 4, 5, 6, Subtract
                  Expanded(
                    child: Row(
                      children: [
                        _buildButton(context, '4', onPressed: () => calculatorNotifier.inputNumber('4')),
                        _buildButton(context, '5', onPressed: () => calculatorNotifier.inputNumber('5')),
                        _buildButton(context, '6', onPressed: () => calculatorNotifier.inputNumber('6')),
                        _buildButton(
                          context,
                          '−',
                          onPressed: () => calculatorNotifier.inputOperator('-'),
                          isOperator: true,
                        ),
                      ],
                    ),
                  ),

                  // Fourth Row - 1, 2, 3, Add
                  Expanded(
                    child: Row(
                      children: [
                        _buildButton(context, '1', onPressed: () => calculatorNotifier.inputNumber('1')),
                        _buildButton(context, '2', onPressed: () => calculatorNotifier.inputNumber('2')),
                        _buildButton(context, '3', onPressed: () => calculatorNotifier.inputNumber('3')),
                        _buildButton(
                          context,
                          '+',
                          onPressed: () => calculatorNotifier.inputOperator('+'),
                          isOperator: true,
                        ),
                      ],
                    ),
                  ),

                  // Fifth Row - 0, Decimal, Equals
                  Expanded(
                    child: Row(
                      children: [
                        _buildButton(context, '0', onPressed: () => calculatorNotifier.inputNumber('0'), flex: 2),
                        _buildButton(context, '.', onPressed: calculatorNotifier.inputDecimal),
                        _buildButton(
                          context,
                          '=',
                          onPressed: calculatorNotifier.calculate,
                          isOperator: true,
                        ),
                      ],
                    ),
                  ),
                ],
              ),
            ),
          ),
        ],
      ),
    );
  }

  Widget _buildButton(
    BuildContext context,
    String text, {
    required VoidCallback onPressed,
    bool isOperator = false,
    int flex = 1,
  }) {
    return Expanded(
      flex: flex,
      child: Padding(
        padding: const EdgeInsets.all(4),
        child: ElevatedButton(
          onPressed: onPressed,
          style: ElevatedButton.styleFrom(
            backgroundColor: isOperator
                ? Theme.of(context).colorScheme.primary
                : Theme.of(context).colorScheme.surface,
            foregroundColor: isOperator
                ? Theme.of(context).colorScheme.onPrimary
                : Theme.of(context).colorScheme.onSurface,
            padding: const EdgeInsets.all(16),
            shape: RoundedRectangleBorder(
              borderRadius: BorderRadius.circular(12),
            ),
            elevation: 2,
          ),
          child: Text(
            text,
            style: Theme.of(context).textTheme.headlineSmall?.copyWith(
              color: isOperator
                  ? Theme.of(context).colorScheme.onPrimary
                  : Theme.of(context).colorScheme.onSurface,
            ),
          ),
        ),
      ),
    );
  }
}

import 'package:riverpod_annotation/riverpod_annotation.dart';
import 'package:math_expressions/math_expressions.dart';
import 'dart:math' as math;

import 'package:a_scientific_calculator_application_to_perform_mor/features/calculator/models/calculator_state.dart';

part 'calculator_provider.g.dart';

@riverpod
class Calculator extends _$Calculator {
  @override
  CalculatorState build() {
    return const CalculatorState(display: '0');
  }

  void inputNumber(String number) {
    final currentState = state;

    if (currentState.hasError) {
      clear();
      return;
    }

    if (currentState.display == '0' || currentState.display == 'Error') {
      state = currentState.copyWith(
        display: number,
        expression: currentState.expression + number,
      );
    } else {
      state = currentState.copyWith(
        display: currentState.display + number,
        expression: currentState.expression + number,
      );
    }
  }

  void inputOperator(String operator) {
    final currentState = state;

    if (currentState.hasError) return;

    // Don't allow operators if display is empty or already ends with operator
    if (currentState.display.isEmpty || 
        currentState.display.endsWith('+') ||
        currentState.display.endsWith('-') ||
        currentState.display.endsWith('*') ||
        currentState.display.endsWith('/')) {
      return;
    }

    state = currentState.copyWith(
      display: currentState.display + operator,
      expression: currentState.expression + operator,
    );
  }

  void inputDecimal() {
    final currentState = state;

    if (currentState.hasError) return;

    // Check if current number already has a decimal
    final parts = currentState.display.split(RegExp(r'[+\-*/]'));
    final lastPart = parts.isNotEmpty ? parts.last : '';

    if (!lastPart.contains('.')) {
      if (currentState.display.isEmpty || currentState.display == '0') {
        state = currentState.copyWith(
          display: '0.',
          expression: currentState.expression + '0.',
        );
      } else {
        state = currentState.copyWith(
          display: currentState.display + '.',
          expression: currentState.expression + '.',
        );
      }
    }
  }

  void squareRoot() {
    final currentState = state;

    if (currentState.hasError) {
      clear();
      return;
    }

    try {
      double value;

      // If there's an expression, evaluate it first
      if (currentState.expression.isNotEmpty) {
        final parser = Parser();
        final exp = parser.parse(currentState.expression);
        final contextModel = ContextModel();
        value = exp.evaluate(EvaluationType.REAL, contextModel);
      } else if (currentState.display.isNotEmpty && currentState.display != '0') {
        value = double.parse(currentState.display);
      } else {
        value = 0;
      }

      if (value < 0) {
        state = currentState.copyWith(
          display: 'Error',
          hasError: true,
          errorMessage: 'Cannot calculate square root of negative number',
        );
        return;
      }

      final result = math.sqrt(value);
      final resultString = result == result.toInt() 
          ? result.toInt().toString() 
          : result.toString();

      state = currentState.copyWith(
        display: resultString,
        expression: '',
        hasError: false,
        errorMessage: '',
      );
    } catch (e) {
      state = currentState.copyWith(
        display: 'Error',
        hasError: true,
        errorMessage: 'Invalid expression',
      );
    }
  }

  void calculate() {
    final currentState = state;

    if (currentState.hasError || currentState.expression.isEmpty) return;

    try {
      final parser = Parser();
      final exp = parser.parse(currentState.expression);
      final contextModel = ContextModel();
      final result = exp.evaluate(EvaluationType.REAL, contextModel);

      final resultString = result == result.toInt() 
          ? result.toInt().toString() 
          : result.toString();

      state = currentState.copyWith(
        display: resultString,
        expression: '',
        hasError: false,
        errorMessage: '',
      );
    } catch (e) {
      state = currentState.copyWith(
        display: 'Error',
        hasError: true,
        errorMessage: 'Invalid expression',
      );
    }
  }

  void clear() {
    state = const CalculatorState(display: '0');
  }

  void backspace() {
    final currentState = state;

    if (currentState.hasError) {
      clear();
      return;
    }

    if (currentState.display.length > 1) {
      state = currentState.copyWith(
        display: currentState.display.substring(0, currentState.display.length - 1),
        expression: currentState.expression.isNotEmpty 
            ? currentState.expression.substring(0, currentState.expression.length - 1)
            : '',
      );
    } else {
      state = currentState.copyWith(display: '0', expression: '');
    }
  }
}

