        actions: [
          IconButton(
            icon: const Icon(Icons.history),
            onPressed: () => _showHistory(context, calculatorState.history),
          ),
          IconButton(
            icon: const Icon(Icons.settings),
            onPressed: () => Navigator.pushNamed(context, '/settings'),
          ),
        ],
      ),
      body: Column(
        children: [
          // Calculator Type Selector
          _buildCalculatorTypeSelector(calculatorNotifier, calculatorState),

          // Display
          Container(
            width: double.infinity,
            padding: const EdgeInsets.all(24),
            color: Theme.of(context).colorScheme.surface,
            child: Column(
              crossAxisAlignment: CrossAxisAlignment.end,
              children: [
                if (calculatorState.expression.isNotEmpty)
                  Text(
                    calculatorState.expression,
                    style: Theme.of(context).textTheme.bodyMedium?.copyWith(
                      color: Theme.of(context).colorScheme.onSurface.withOpacity(0.6),
                    ),
                  ),
                Text(
                  calculatorState.display,
                  style: Theme.of(context).textTheme.headlineLarge?.copyWith(
                    fontWeight: FontWeight.bold,
                  ),
                ),
              ],
            ),
          ),

          // Buttons
          Expanded(
            child: _buildButtonGrid(calculatorNotifier, calculatorState),
          ),
        ],
      ),
    );
  }

  Widget _buildCalculatorTypeSelector(
    CalculatorNotifier calculatorNotifier,
    CalculatorState calculatorState,
  ) {
    return Container(
      height: 60,
      padding: const EdgeInsets.symmetric(horizontal: 16),
      child: ListView(
        scrollDirection: Axis.horizontal,
        children: CalculationType.values.map((type) {
          final isSelected = calculatorState.currentType == type;
          return Padding(
            padding: const EdgeInsets.symmetric(horizontal: 4),
            child: ChoiceChip(
              label: Text(_getCalculationTypeName(type)),
              selected: isSelected,
              onSelected: (selected) {
                if (selected) {
                  calculatorNotifier.setCalculationType(type);
                }
              },
            ),
          );
        }).toList(),
      ),
    );
  }

  Widget _buildButtonGrid(
    CalculatorNotifier calculatorNotifier,
    CalculatorState calculatorState,
  ) {
    final buttons = _getButtonsForType(calculatorState.currentType);

    return GridView.builder(
      padding: const EdgeInsets.all(16),
      gridDelegate: SliverGridDelegateWithFixedCrossAxisCount(
        crossAxisCount: _getCrossAxisCount(calculatorState.currentType),
        crossAxisSpacing: 8,
        mainAxisSpacing: 8,
        childAspectRatio: 1.2,
      ),
      itemCount: buttons.length,
      itemBuilder: (context, index) {
        final button = buttons[index];
        return _buildButton(
          context,
          button['text'] as String,
          button['onPressed'] as VoidCallback,
          color: button['color'] as Color?,
        );
      },
    );
  }

  Widget _buildButton(
    BuildContext context,
    String text,
    VoidCallback onPressed,
    {Color? color}
  ) {
    return ElevatedButton(
      onPressed: onPressed,
      style: ElevatedButton.styleFrom(
        backgroundColor: color,
        padding: const EdgeInsets.all(8),
        shape: RoundedRectangleBorder(
          borderRadius: BorderRadius.circular(8),
        ),
      ),
      child: Text(
        text,
        style: Theme.of(context).textTheme.titleMedium?.copyWith(
          fontWeight: FontWeight.bold,
        ),
      ),
    );
  }

  List<Map<String, dynamic>> _getButtonsForType(CalculationType type) {
    switch (type) {
      case CalculationType.basic:
        return _getBasicButtons();
      case CalculationType.scientific:
        return _getScientificButtons();
      case CalculationType.calculus:
        return _getCalculusButtons();
      case CalculationType.equation:
        return _getEquationButtons();
    }
  }

