      {'text': '=', 'onPressed': () {}, 'color': Colors.green[400]},
    ];
  }

  List<Map<String, dynamic>> _getScientificButtons() {
    return [
      // Add scientific calculator buttons
      {'text': 'sin', 'onPressed': () {}, 'color': Colors.purple[200]},
      {'text': 'cos', 'onPressed': () {}, 'color': Colors.purple[200]},
